import pika

# Connection parameters
HOST = 'localhost'
PORT = 5672
QUEUE_NAME = 'task_queue'

# Publisher
connection = pika.BlockingConnection(pika.ConnectionParameters(host=HOST, port=PORT))
channel = connection.channel()
channel.queue_declare(queue=QUEUE_NAME)

# Task message
task_message = 'Perform task'

# Send task message to queue
channel.basic_publish(exchange='', routing_key=QUEUE_NAME, body=task_message.encode())
print(f'Sent task message: {task_message}')

# Consumer
connection = pika.BlockingConnection(pika.ConnectionParameters(host=HOST, port=PORT))
channel = connection.channel()
channel.queue_declare(queue=QUEUE_NAME)

# Consume task messages
while True:
    method_frame, header_frame, body = channel.basic_get(queue=QUEUE_NAME)
    if not method_frame:
        break
    task_message = body.decode()
    print(f'Consumed task message: {task_message}')
    # Process task message here
    channel.basic_ack(delivery_tag=method_frame.delivery_tag)

# Close connections
connection.close()